<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Bouncing‑Ball Playground</title>
<style>
  html,body{
    height:100%;margin:0;background:#111;color:#ddd;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;align-items:center;justify-content:center;
    flex-direction:column;
  }
  #controls{
    margin:10px;
  }
  button{
    background:#333;border:none;color:#ddd;padding:8px 12px;
    margin:0 4px;cursor:pointer;border-radius:4px;
  }
  button:hover{background:#444;}
  canvas{
    background:#222;
    display:block;
    box-shadow:0 0 10px #000;
  }
</style>
</head>
<body>
<div id="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sim" width="500" height="500"></canvas>

<script>
(() => {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const w = canvas.width, h = canvas.height;
  const gravity = 0.5;          // px per frame²
  const restitution = 0.8;      // energy loss on bounce
  const balls = [];

  // Utility: random color
  const randColor = () => {
    const hue = Math.floor(Math.random()*360);
    return `hsl(${hue},80%,60%)`;
  };

  // API
  window.sim = {
    w, h,
    balls(){ return balls.map(b=>({x:b.x,y:b.y,vx:b.vx,vy:b.vy,r:b.r})); },
    addBall(x,y,vx=0,vy=0,r){
      const radius = r|| (10+Math.random()*10);
      balls.push({x,y,vx,vy,r:radius,color:randColor()});
      draw();
    },
    clear(){
      balls.length = 0;
      draw();
    },
    step(dt=1){
      for(let i=0;i<dt;i++) update();
      draw();
    }
  };

  function update(){
    for(const b of balls){
      // apply gravity
      b.vy += gravity;

      // move
      b.x += b.vx;
      b.y += b.vy;

      // left wall
      if(b.x - b.r < 0){
        b.x = b.r;
        b.vx = -b.vx * restitution;
      }
      // right wall
      if(b.x + b.r > w){
        b.x = w - b.r;
        b.vx = -b.vx * restitution;
      }
      // ceiling
      if(b.y - b.r < 0){
        b.y = b.r;
        b.vy = -b.vy * restitution;
      }
      // floor
      if(b.y + b.r > h){
        b.y = h - b.r;
        b.vy = -b.vy * restitution;
        // small threshold to stop endless micro‑bounces
        if(Math.abs(b.vy) < 0.1) b.vy = 0;
      }
    }
  }

  function draw(){
    ctx.clearRect(0,0,w,h);
    for(const b of balls){
      ctx.beginPath();
      ctx.arc(b.x,b.y,b.r,0,Math.PI*2);
      ctx.fillStyle = b.color;
      ctx.fill();
      ctx.strokeStyle = '#000';
      ctx.stroke();
    }
  }

  // UI interactions
  document.getElementById('drop').addEventListener('click',()=>{
    const x = Math.random()*(w-40)+20;
    const y = 20;
    sim.addBall(x,y,0,0);
  });

  let playing = true;
  const playBtn = document.getElementById('play');
  playBtn.addEventListener('click',()=>{
    playing = !playing;
    playBtn.textContent = playing ? 'Pause' : 'Play';
    if(playing) requestAnimationFrame(loop);
  });

  document.getElementById('clear').addEventListener('click',()=>sim.clear());

  canvas.addEventListener('click',e=>{
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    sim.addBall(x,y,0,0);
  });

  // animation loop
  function loop(){
    if(!playing) return;
    sim.step(1);
    requestAnimationFrame(loop);
  }
  requestAnimationFrame(loop);
})();
</script>
</body>
</html>
